import os
import base64
import pyotp
from flask import Flask, render_template_string, request, redirect, url_for, session, jsonify, flash
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = os.getenv('SECRET_KEY', 'a_super_secret_key_for_dev')
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///auth_system.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

# --- Database Model ---
class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password_hash = db.Column(db.String(128), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(16)) # base32 encoded secret

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

    def set_mfa_secret(self):
        # Generate a random 16-character base32 secret
        self.mfa_secret = base64.b32encode(os.urandom(10)).decode('utf-8')[:16] # Ensure it's 16 chars for Google Authenticator

    def get_totp_uri(self, name='FlaskAuth'):
        return pyotp.totp.TOTP(self.mfa_secret).provisioning_uri(
            name=self.username,
            issuer_name='FlaskAuth'
        )

    def verify_otp(self, otp_code):
        totp = pyotp.TOTP(self.mfa_secret)
        return totp.verify(otp_code)

    def __repr__(self):
        return f'<User {self.username}>'

# --- Helper Functions and Decorators ---
with app.app_context():
    db.create_all()

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            flash('Please log in to access this page.', 'warning')
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

