# 1. Registration
@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        existing_user = User.query.filter_by(username=username).first()
        if existing_user:
            flash('Username already exists.', 'danger')
            return redirect(url_for('register'))

        new_user = User(username=username)
        new_user.set_password(password)
        db.session.add(new_user)
        db.session.commit()
        flash('Registration successful! Please log in.', 'success')
        return redirect(url_for('login'))
    return render_template_string("""
        <!doctype html>
        <title>Register</title>
        <h1>Register</h1>
        {% with messages = get_flashed_messages(with_categories=true) %}
          {% if messages %}
            <ul class=flashes>
            {% for category, message in messages %}
              <li class="{{ category }}">{{ message }}</li>
            {% endfor %}
            </ul>
          {% endif %}
        {% endwith %}
        <form method="POST">
            <label for="username">Username:</label><br>
            <input type="text" id="username" name="username" required><br>
            <label for="password">Password:</label><br>
            <input type="password" id="password" name="password" required><br><br>
            <input type="submit" value="Register">
        </form>
        <p>Already have an account? <a href="{{ url_for('login') }}">Login here</a>.</p>
    """)

# 2. Web Login (with optional MFA)
@app.route('/login', methods=['GET', 'POST'])
def login():
    if 'user_id' in session:
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        user = User.query.filter_by(username=username).first()

        if user and user.check_password(password):
            session.pop('user_id_pending_mfa', None) # Clear any pending MFA state

            if user.mfa_enabled:
                session['user_id_pending_mfa'] = user.id
                flash('MFA required. Please enter your OTP.', 'info')
                return redirect(url_for('verify_mfa'))
            else:
                session['user_id'] = user.id
                flash('Login successful!', 'success')
                return redirect(url_for('dashboard'))
        else:
            flash('Invalid username or password.', 'danger')
    
    return render_template_string("""
        <!doctype html>
        <title>Login</title>
        <h1>Login</h1>
        {% with messages = get_flashed_messages(with_categories=true) %}
          {% if messages %}
            <ul class=flashes>
            {% for category, message in messages %}
              <li class="{{ category }}">{{ message }}</li>
            {% endfor %}
            </ul>
          {% endif %}
        {% endwith %}
        <form method="POST">
            <label for="username">Username:</label><br>
            <input type="text" id="username" name="username" required><br>
            <label for="password">Password:</label><br>
            <input type="password" id="password" name="password" required><br><br>
            <input type="submit" value="Login">
        </form>
        <p>Don't have an account? <a href="{{ url_for('register') }}">Register here</a>.</p>
    """)

# 3. MFA Verification
@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'user_id' in session: # User is already fully logged in
        return redirect(url_for('dashboard'))

    user_id_pending_mfa = session.get('user_id_pending_mfa')
    if not user_id_pending_mfa:
        flash('MFA process not initiated or session expired. Please log in again.', 'warning')
        return redirect(url_for('login'))

    user = User.query.get(user_id_pending_mfa)
    if not user or not user.mfa_enabled:
        # Should not happen if logic is correct, but good for safety
        flash('Error with MFA setup. Please log in again.', 'danger')
        session.pop('user_id_pending_mfa', None)
        return redirect(url_for('login'))

    if request.method == 'POST':
        otp_code = request.form['otp_code']
        if user.verify_otp(otp_code):
            session.pop('user_id_pending_mfa', None)
            session['user_id'] = user.id
            flash('MFA successful! You are now logged in.', 'success')
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid OTP. Please try again.', 'danger')

    return render_template_string("""
        <!doctype html>
        <title>Verify MFA</title>
        <h1>Verify MFA</h1>
        {% with messages = get_flashed_messages(with_categories=true) %}
          {% if messages %}
            <ul class=flashes>
            {% for category, message in messages %}
              <li class="{{ category }}">{{ message }}</li>
            {% endfor %}
            </ul>
          {% endif %}
        {% endwith %}
        <p>Please enter the One-Time Password from your authenticator app.</p>
        <form method="POST">
            <label for="otp_code">OTP:</label><br>
            <input type="text" id="otp_code" name="otp_code" required><br><br>
            <input type="submit" value="Verify OTP">
        </form>
        <p><a href="{{ url_for('logout') }}">Cancel and Logout</a></p>
    """)

